import{c as s,Q as n,j as p,m as t}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"对象存储:Bucket、Object、S3、R2、OSS 到底解决什么问题","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/15-对象存储.md","filePath":"cloudBasicsLearning/15-对象存储.md","lastUpdated":1779015580000}'),e={name:"cloudBasicsLearning/15-对象存储.md"};function l(i,a,d,c,o,r){return n(),p("div",null,[...a[0]||(a[0]=[t(`<h1 id="对象存储-bucket、object、s3、r2、oss-到底解决什么问题" tabindex="-1">对象存储:Bucket、Object、S3、R2、OSS 到底解决什么问题 <a class="header-anchor" href="#对象存储-bucket、object、s3、r2、oss-到底解决什么问题" aria-label="Permalink to &quot;对象存储:Bucket、Object、S3、R2、OSS 到底解决什么问题&quot;">​</a></h1><p>对象存储经常被初学者理解成&quot;云上的硬盘&quot;。这个理解能帮你入门,但很快会误导你。对象存储不是给程序像本地磁盘一样随便 <code>open</code>、<code>write</code>、<code>append</code> 的文件系统,它更像一个通过 API 读写的大型文件仓库。</p><blockquote><p>一句话先记住:对象存储负责低成本、可扩展地保存文件,适合图片、视频、备份、日志、导出文件、静态站资源,不适合当数据库用,也不适合频繁修改小片段的文件。</p></blockquote><hr><h2 id="一、一句话解释" tabindex="-1">一、一句话解释 <a class="header-anchor" href="#一、一句话解释" aria-label="Permalink to &quot;一、一句话解释&quot;">​</a></h2><p>对象存储里最核心的两个词是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bucket:一个存储桶,类似一个文件仓库或命名空间</span></span>
<span class="line"><span>Object:一个对象,通常就是一个文件加上一些元数据</span></span></code></pre></div><p>一个对象一般包含:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key:路径式名称,例如 uploads/2026/05/avatar.png</span></span>
<span class="line"><span>body:文件内容</span></span>
<span class="line"><span>metadata:Content-Type、缓存时间、自定义标签</span></span>
<span class="line"><span>permission:公共读、私有、临时授权</span></span>
<span class="line"><span>version:有些平台支持版本控制</span></span></code></pre></div><p>典型产品包括:</p><ul><li>AWS S3</li><li>Cloudflare R2</li><li>阿里云 OSS</li><li>腾讯云 COS</li><li>Google Cloud Storage</li><li>MinIO 这类 S3 兼容自建方案</li></ul><p>对象存储最容易和三类东西混淆。</p><p>第一,和服务器硬盘混淆。服务器硬盘适合程序本地读写,但容量、备份、迁移、扩容都要自己操心。对象存储通过 HTTP API 访问,容量可以很大,但不是本地文件系统。</p><p>第二,和网盘混淆。网盘面向人,强调同步、预览、分享。对象存储面向程序,强调 API、权限、生命周期、CDN、计费。</p><p>第三,和数据库混淆。数据库适合查询结构化数据,例如用户、订单、账单。对象存储适合保存文件本体,例如头像、合同 PDF、导出 CSV。你可以把文件地址存在数据库里,但不要把对象存储当成可以随意查询的表。</p><hr><h2 id="二、放在系统哪里" tabindex="-1">二、放在系统哪里 <a class="header-anchor" href="#二、放在系统哪里" aria-label="Permalink to &quot;二、放在系统哪里&quot;">​</a></h2><p>对象存储通常放在应用的文件层:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器</span></span>
<span class="line"><span>  -&gt; 前端页面</span></span>
<span class="line"><span>  -&gt; 后端 API</span></span>
<span class="line"><span>  -&gt; 对象存储</span></span></code></pre></div><p>常见模式有两种。</p><p>第一种,后端中转上传:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器上传文件</span></span>
<span class="line"><span>  -&gt; 后端接收文件</span></span>
<span class="line"><span>  -&gt; 后端上传到对象存储</span></span>
<span class="line"><span>  -&gt; 后端把 object key 写入数据库</span></span></code></pre></div><p>这个方式简单,权限容易控制,但大文件会占用后端带宽和执行时间。</p><p>第二种,浏览器直传对象存储:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器请求上传凭证</span></span>
<span class="line"><span>  -&gt; 后端生成临时签名 URL</span></span>
<span class="line"><span>  -&gt; 浏览器直接上传到对象存储</span></span>
<span class="line"><span>  -&gt; 后端记录文件信息</span></span></code></pre></div><p>这个方式更适合图片、视频、大文件。后端只负责授权和记录,不搬运文件本体。</p><p>对象存储常和 CDN 搭配:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户访问图片</span></span>
<span class="line"><span>  -&gt; CDN</span></span>
<span class="line"><span>  -&gt; 缓存命中:直接返回</span></span>
<span class="line"><span>  -&gt; 缓存未命中:回源到对象存储</span></span></code></pre></div><p>这样可以减少对象存储的读取压力和跨地域延迟。静态网站托管也常用这个模式:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>构建产物</span></span>
<span class="line"><span>  -&gt; 上传到对象存储 Bucket</span></span>
<span class="line"><span>  -&gt; CDN 加速</span></span>
<span class="line"><span>  -&gt; 用户访问 HTML / JS / CSS</span></span></code></pre></div><p>在系统设计里,对象存储通常保存&quot;大块非结构化数据&quot;,数据库保存&quot;可查询的结构化索引&quot;:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据库:</span></span>
<span class="line"><span>  file_id</span></span>
<span class="line"><span>  user_id</span></span>
<span class="line"><span>  object_key</span></span>
<span class="line"><span>  size</span></span>
<span class="line"><span>  content_type</span></span>
<span class="line"><span>  created_at</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对象存储:</span></span>
<span class="line"><span>  uploads/user-123/avatar.png</span></span></code></pre></div><hr><h2 id="三、常见套餐和使用限制" tabindex="-1">三、常见套餐和使用限制 <a class="header-anchor" href="#三、常见套餐和使用限制" aria-label="Permalink to &quot;三、常见套餐和使用限制&quot;">​</a></h2><p>对象存储的计费和限制通常拆成好几个维度:</p><table tabindex="0"><thead><tr><th>限制项</th><th>说明</th><th>常见风险</th></tr></thead><tbody><tr><td>存储容量</td><td>文件占用多少 GB / TB</td><td>备份、日志、视频长期堆积</td></tr><tr><td>出站流量</td><td>文件被用户下载产生的流量</td><td>热门图片、安装包、视频最容易超</td></tr><tr><td>请求次数</td><td>PUT、GET、LIST、DELETE 等操作</td><td>小文件多、列表频繁、爬虫访问会放大</td></tr><tr><td>跨地域流量</td><td>不同区域之间传输数据</td><td>应用和 Bucket 不在同一区域</td></tr><tr><td>生命周期规则</td><td>自动转低频、归档、删除</td><td>配错可能导致文件过早归档或删除</td></tr><tr><td>数据取回费</td><td>归档或低频存储取回可能收费</td><td>以为便宜,恢复时才发现贵</td></tr><tr><td>最小存储时间</td><td>某些低频层要求至少存一段时间</td><td>频繁删除反而不省钱</td></tr><tr><td>公网访问权限</td><td>公共读、私有读、签名 URL</td><td>配错会泄露文件或导致 403</td></tr></tbody></table><p>S3、R2、OSS 这类产品名字不同,但你看套餐时都应该问同一组问题:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>存进去多少钱?</span></span>
<span class="line"><span>取出来多少钱?</span></span>
<span class="line"><span>请求一次多少钱?</span></span>
<span class="line"><span>跨区域多少钱?</span></span>
<span class="line"><span>是否有免费额度?</span></span>
<span class="line"><span>是否有出口流量优惠?</span></span>
<span class="line"><span>是否和 CDN 绑定后价格不同?</span></span>
<span class="line"><span>删除、归档、恢复有没有隐藏成本?</span></span></code></pre></div><p>Cloudflare R2 经常被拿来和 S3 对比,重点通常在出口流量模型和 S3 兼容 API。阿里云 OSS、腾讯云 COS 在国内业务里常见,优势是国内区域、备案和同厂商服务集成。AWS S3 是事实上的对象存储接口标准,很多工具都支持 S3 API。</p><p>但小团队不要只看&quot;哪个最便宜&quot;。对象存储一旦接入业务,迁移会涉及:</p><ul><li>文件 URL 是否写死</li><li>Bucket 名称和区域</li><li>签名算法和 SDK</li><li>CDN 域名</li><li>CORS 配置</li><li>生命周期策略</li><li>数据库里的 object key</li></ul><p>所以更重要的是选一个你能长期维护、能看懂账单、能设置权限和告警的方案。</p><hr><h2 id="四、小团队建议" tabindex="-1">四、小团队建议 <a class="header-anchor" href="#四、小团队建议" aria-label="Permalink to &quot;四、小团队建议&quot;">​</a></h2><p>对象存储最适合放这些东西:</p><ul><li>用户头像、封面图、附件</li><li>导出的 CSV、PDF、报表</li><li>静态网站构建产物</li><li>备份文件</li><li>日志归档</li><li>安装包、压缩包、公开下载文件</li><li>图片、音频、视频原文件</li></ul><p>不建议放这些东西:</p><ul><li>需要复杂查询的数据</li><li>高频更新的单个 JSON 文件</li><li>需要事务保证的业务数据</li><li>密钥、Token、数据库密码</li><li>没有访问控制的用户隐私文件</li></ul><p>一个保守的小团队架构可以这样设计:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端:上传前向后端申请临时 URL</span></span>
<span class="line"><span>后端:校验用户身份、文件大小、文件类型</span></span>
<span class="line"><span>对象存储:保存文件本体</span></span>
<span class="line"><span>数据库:保存文件记录和 object key</span></span>
<span class="line"><span>CDN:加速公开文件读取</span></span></code></pre></div><p>最低限度的护栏:</p><ul><li>默认 Bucket 私有,只把确实公开的目录或文件公开</li><li>上传前限制文件大小和 MIME 类型</li><li>用户私有文件用短期签名 URL 访问</li><li>不要把永久 AK / SK 放进前端代码</li><li>给 Bucket 设置生命周期规则,清理临时文件和过期导出</li><li>给出站流量和请求数设置预算告警</li><li>对重要文件开启版本控制或定期备份</li><li>文件 URL 不要只存在对象存储里,数据库要有业务记录</li></ul><p>一个典型坑是&quot;用户上传了头像,但旧头像永远不删&quot;。单个头像只有几百 KB,看起来不值一提;用户多了以后,历史头像、失败上传、临时裁剪文件、导出报表会一起堆积。对象存储便宜,但不是无限垃圾桶。</p><p>什么时候该升级或重新设计?</p><ul><li>文件访问量已经成为主要流量成本</li><li>上传文件变大,后端中转开始超时</li><li>需要跨地域访问或合规数据位置</li><li>需要防盗链、图片处理、转码、水印</li><li>需要更细粒度的权限和审计</li><li>备份和恢复流程开始影响业务连续性</li></ul><p>小团队最重要的不是一开始就买高级存储层,而是把&quot;文件本体&quot;和&quot;业务记录&quot;分清楚。文件放对象存储,索引和权限放数据库,访问控制由后端发放。</p><hr><h2 id="五、一句话总结" tabindex="-1">五、一句话总结 <a class="header-anchor" href="#五、一句话总结" aria-label="Permalink to &quot;五、一句话总结&quot;">​</a></h2><p>对象存储是云上保存文件的基础设施:S3、R2、OSS 这类产品解决的是低成本存取大规模文件的问题;看套餐时要同时看容量、出站流量、请求次数、生命周期、权限和跨地域成本。</p>`,59)])])}const g=s(e,[["render",l]]);export{h as __pageData,g as default};
